import pandas as pd
import matplotlib.pyplot as plt

# Read results generated by compare_hrf_svm.py
df = pd.read_csv("hrf_vs_svm_results.csv")

# Graph 1: HRF vs SVM Accuracy

accuracy_df = df[[
    "Dataset",
    "HRF Accuracy (%)",
    "SVM Accuracy (%)"
]]

accuracy_df.set_index("Dataset").plot(
    kind="bar",
    figsize=(12, 6)
)

plt.title("HRF vs SVM Accuracy Comparison")
plt.ylabel("Accuracy (%)")
plt.tight_layout()

plt.savefig("hrf_vs_svm_accuracy.png")

plt.show()

# Graph 2: Accuracy Difference

plt.figure(figsize=(12, 6))

plt.bar(
    df["Dataset"],
    df["Difference (%)"]
)

plt.xticks(rotation=90)

plt.ylabel("Accuracy Difference (%)")
plt.xlabel("Dataset")

plt.title("HRF Advantage over SVM")

plt.tight_layout()

plt.savefig("hrf_vs_svm_difference.png")

plt.show()